// org.apache.commons.lang.CharUtilsTest::testToUnicodeEscaped_char
    public void testToUnicodeEscaped_char() {
        assertEquals("\\u0041", CharUtils.unicodeEscaped('A'));

        for (int i = 0; i < 196; i++) {
